B.Lr=s(["  CREATE TABLE recipes (\n      id                 TEXT PRIMARY KEY,\n      title              TEXT NOT NULL,\n      description        TEXT,\n      servings           INTEGER,\n      prep_time_minutes  INTEGER,\n      cook_time_minutes  INTEGER,\n      is_favorite        INTEGER NOT NULL DEFAULT 0,\n      created_at         TEXT NOT NULL,\n      updated_at         TEXT NOT NULL\n  )\n  ","  CREATE TABLE ingredients (\n      id          TEXT PRIMARY KEY,\n      recipe_id   TEXT NOT NULL REFERENCES recipes(id) ON DELETE CASCADE,\n      name        TEXT NOT NULL,\n      quantity    REAL,\n      unit        TEXT,\n      sort_order  INTEGER NOT NULL DEFAULT 0,\n      created_at  TEXT NOT NULL,\n      updated_at  TEXT NOT NULL\n  )\n  ","  CREATE TABLE recipe_steps (\n      id                 TEXT PRIMARY KEY,\n      recipe_id          TEXT NOT NULL REFERENCES recipes(id) ON DELETE CASCADE,\n      step_number        INTEGER NOT NULL,\n      instruction        TEXT NOT NULL,\n      duration_minutes   INTEGER,\n      created_at         TEXT NOT NULL,\n      updated_at         TEXT NOT NULL\n  )\n  ","  CREATE TABLE recipe_images (\n      id          TEXT PRIMARY KEY,\n      recipe_id   TEXT NOT NULL REFERENCES recipes(id) ON DELETE CASCADE,\n      file_path   TEXT NOT NULL,\n      is_primary  INTEGER NOT NULL DEFAULT 0,\n      sort_order  INTEGER NOT NULL DEFAULT 0,\n      created_at  TEXT NOT NULL,\n      updated_at  TEXT NOT NULL\n  )\n  ","  CREATE TABLE tags (\n      id          TEXT PRIMARY KEY,\n      name        TEXT NOT NULL UNIQUE,\n      created_at  TEXT NOT NULL,\n      updated_at  TEXT NOT NULL\n  )\n  ","  CREATE TABLE recipe_tags (\n      recipe_id   TEXT NOT NULL REFERENCES recipes(id) ON DELETE CASCADE,\n      tag_id      TEXT NOT NULL REFERENCES tags(id) ON DELETE CASCADE,\n      created_at  TEXT NOT NULL,\n      PRIMARY KEY (recipe_id, tag_id)\n  )\n  ","  CREATE TABLE recipe_versions (\n      id               TEXT PRIMARY KEY,\n      recipe_id        TEXT NOT NULL REFERENCES recipes(id) ON DELETE CASCADE,\n      version_number   INTEGER NOT NULL,\n      note             TEXT,\n      snapshot_json    TEXT NOT NULL,\n      created_at       TEXT NOT NULL,\n      UNIQUE (recipe_id, version_number)\n  )\n  ","  CREATE TABLE shopping_list_items (\n      id          TEXT PRIMARY KEY,\n      name        TEXT NOT NULL,\n      quantity    REAL,\n      unit        TEXT,\n      category    TEXT,\n      is_checked  INTEGER NOT NULL DEFAULT 0,\n      recipe_id   TEXT REFERENCES recipes(id) ON DELETE SET NULL,\n      created_at  TEXT NOT NULL,\n      updated_at  TEXT NOT NULL\n  )\n  ","CREATE INDEX idx_recipes_title ON recipes(title)","CREATE INDEX idx_recipes_is_favorite ON recipes(is_favorite)","CREATE INDEX idx_ingredients_recipe_id ON ingredients(recipe_id)","CREATE INDEX idx_recipe_steps_recipe_id ON recipe_steps(recipe_id)","CREATE INDEX idx_recipe_images_recipe_id ON recipe_images(recipe_id)","CREATE INDEX idx_recipe_tags_tag_id ON recipe_tags(tag_id)","CREATE INDEX idx_recipe_versions_recipe_id ON recipe_versions(recipe_id)","CREATE INDEX idx_shopping_list_items_recipe_id ON shopping_list_items(recipe_id)","CREATE INDEX idx_shopping_list_items_is_checked ON shopping_list_items(is_checked)","CREATE INDEX idx_shopping_list_items_category ON shopping_list_items(category)"],t.s)
